import{c as a,Q as o,j as t,m as l}from"./chunks/framework.D9IbVcwA.js";const h=JSON.parse('{"title":"Prompt: 理解 Cinux 项目","description":"","frontmatter":{},"headers":[],"relativePath":"ai_prompts/prompt_understand_project.md","filePath":"ai_prompts/prompt_understand_project.md","lastUpdated":1779670442000}'),i={name:"ai_prompts/prompt_understand_project.md"};function r(d,e,c,n,s,p){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="prompt-理解-cinux-项目" tabindex="-1">Prompt: 理解 Cinux 项目 <a class="header-anchor" href="#prompt-理解-cinux-项目" aria-label="Permalink to &quot;Prompt: 理解 Cinux 项目&quot;">​</a></h1><h2 id="目的" tabindex="-1">目的 <a class="header-anchor" href="#目的" aria-label="Permalink to &quot;目的&quot;">​</a></h2><p>让 AI 快速理解项目全貌，能够回答关于架构、模块、构建等方面的问题。</p><h2 id="流程" tabindex="-1">流程 <a class="header-anchor" href="#流程" aria-label="Permalink to &quot;流程&quot;">​</a></h2><h3 id="第一步-读项目入口" tabindex="-1">第一步：读项目入口 <a class="header-anchor" href="#第一步-读项目入口" aria-label="Permalink to &quot;第一步：读项目入口&quot;">​</a></h3><ul><li>读 <code>CLAUDE.md</code>（AI 主入口和工作流定义）</li><li>读 <code>document/todo/README.md</code>（路线图和 Feature 域划分）</li></ul><h3 id="第二步-浏览源码结构" tabindex="-1">第二步：浏览源码结构 <a class="header-anchor" href="#第二步-浏览源码结构" aria-label="Permalink to &quot;第二步：浏览源码结构&quot;">​</a></h3><p>按以下顺序浏览目录，理解模块组织：</p><ol><li><code>boot/</code> — 启动流程（BIOS → real mode → protected mode → long mode → kernel entry）</li><li><code>kernel/arch/x86_64/</code> — 架构相关（GDT、IDT、上下文切换）</li><li><code>kernel/mm/</code> — 内存管理（PMM、VMM、Heap、地址空间）</li><li><code>kernel/proc/</code> — 进程管理（调度器、上下文、同步原语）</li><li><code>kernel/drivers/</code> — 驱动（串口、VGA、键盘、AHCI、PCI、PIT）</li><li><code>kernel/fs/</code> — 文件系统（VFS、ext2、ramdisk）</li><li><code>kernel/gui/</code> — GUI（canvas、窗口管理器、位图、桌面）</li><li><code>kernel/ipc/</code> — 进程间通信（pipe）</li><li><code>kernel/syscall/</code> — 系统调用</li><li><code>kernel/lib/</code> — 基础设施库（kprintf、string、atomic 等）</li></ol><h3 id="第三步-读代码规范" tabindex="-1">第三步：读代码规范 <a class="header-anchor" href="#第三步-读代码规范" aria-label="Permalink to &quot;第三步：读代码规范&quot;">​</a></h3><ul><li>读 <code>document/ai_prompts/code_conventions.md</code></li></ul><h3 id="第四步-读构建系统" tabindex="-1">第四步：读构建系统 <a class="header-anchor" href="#第四步-读构建系统" aria-label="Permalink to &quot;第四步：读构建系统&quot;">​</a></h3><ul><li>读根 <code>CMakeLists.txt</code>，理解整体构建结构</li><li>读 <code>kernel/CMakeLists.txt</code>，理解内核构建</li><li>读 <code>test/CMakeLists.txt</code>，理解测试构建</li></ul><h2 id="约束" tabindex="-1">约束 <a class="header-anchor" href="#约束" aria-label="Permalink to &quot;约束&quot;">​</a></h2><ul><li><strong>不猜测</strong>，以源码为准</li><li>遇到不确定的，读对应源文件确认</li><li>项目使用 C++23 freestanding，禁用标准库、异常、RTTI</li><li>所有汇编使用 AT&amp;T 语法</li></ul>',15)])])}const u=a(i,[["render",r]]);export{h as __pageData,u as default};
